/* Minimal opcode constants used by the prototype materializer. */
enum {
  SPON_OP_MOVE = 0,
  SPON_OP_LOADI = 1,
  SPON_OP_LOADF = 2,
  SPON_OP_LOADK = 3,
  SPON_OP_LOADKX = 4,
  SPON_OP_LOADFALSE = 5,
  SPON_OP_LFALSESKIP = 6,
  SPON_OP_LOADTRUE = 7,
  SPON_OP_LOADNIL = 8,
  SPON_OP_ADDI = 21,
  SPON_OP_MODK = 25,
  SPON_OP_DIVK = 27,
  SPON_OP_IDIVK = 28,
  SPON_OP_SHLI = 32,
  SPON_OP_SHRI = 33,
  SPON_OP_MOD = 37,
  SPON_OP_DIV = 39,
  SPON_OP_IDIV = 40
};

enum {
  SPON_LUA_VNIL = 0,
  SPON_LUA_VFALSE = 1,
  SPON_LUA_VNUMINT = 3,
  SPON_LUA_VTRUE = 17,
  SPON_LUA_VNUMFLT = 19
};

#define SPON_FACT_I64_SLOT(slot_) (((SponFactSig)1) << (slot_))

typedef struct SponL1Op {
  uint32_t opcode;
  int32_t a;
  int32_t b;
  int32_t c;
  int32_t bx;
  int32_t ax;
  int32_t sbx;
  int32_t sj;
  int64_t k_i64;
} SponL1Op;

typedef struct SponL1Image {
  uint8_t *code;
  size_t code_size;
  uint32_t n_choices;
  SponSelectStats select_stats;
} SponL1Image;

void spon_l1_image_init(SponL1Image *img);
void spon_l1_image_free(SponL1Image *img);

/*
 * Select L1 native stencils from the generated bank and copy/link/patch them
 * into one executable image. This is a prototype projection interpreter step:
 * bytecode+facts -> bank choices -> native image. It does not run SSA.
 */
int spon_l1_project(const SponL1Op *ops, uint32_t start, uint32_t end,
                    SponFactSig entry_sig, SponFactSig observed_sig,
                    SponL1Image *out_img);

/* Execute a previously projected image. Returns ctx->exit_kind. */
uint32_t spon_l1_run(const SponL1Image *img, SponExecCtx *ctx);

/* Convenience function: project, run once, then free the image. */
uint32_t spon_l1_interpret_once(const SponL1Op *ops, uint32_t start, uint32_t end,
                                SponFactSig entry_sig, SponFactSig observed_sig,
                                SponExecCtx *ctx);

#ifdef __cplusplus
}
#endif

#endif

#!/usr/bin/env luajit

package.path = "./experiments/lua_interpreter_vm/spongejit/?.lua;" .. package.path

local ffi = require("ffi")
local Facts = require("src.facts")
local SSA = require("src.ssa")
local StencilLower = require("src.stencil_lower")

ffi.cdef[[
typedef unsigned long size_t;
typedef struct SponTValueABI {
  unsigned long long value_;
  unsigned char tt_;
} SponTValueABI;
typedef struct SponExecCtx {
  void *stack;
  SponTValueABI *k;
  SponTValueABI scratch[256];
  uint32_t exit_kind;
  uint32_t exit_pc;
  uint32_t exit_op_idx;
  uint32_t exit_hole;
} SponExecCtx;
void *mmap(void *addr, size_t length, int prot, int flags, int fd, long offset);
int munmap(void *addr, size_t length);
void *memcpy(void *dest, const void *src, size_t n);
]]

local function assert_eq(a, b, msg) if a ~= b then error((msg or "assert_eq failed") .. ": " .. tostring(a) .. " ~= " .. tostring(b), 2) end end
local function assert_true(x, msg) if not x then error(msg or "assert_true failed", 2) end end

local function hex_to_buf(hex)
  local n = #hex / 2
  local buf = ffi.new("uint8_t[?]", n)
  local i = 0
  for pair in hex:gmatch("%x%x") do buf[i] = tonumber(pair, 16); i = i + 1 end
  return buf, n
end

local function write_i64(buf, off, v)
  local n = tonumber(v)
  local neg = n < 0
  if neg then n = -n end
  local bytes = {}
  for i = 0, 7 do
    bytes[i] = n % 256
    n = math.floor(n / 256)
  end
  if neg then
    local carry = 1
    for i = 0, 7 do
      local x = 255 - bytes[i] + carry
      if x >= 256 then x = x - 256; carry = 1 else carry = 0 end
      bytes[i] = x
    end
  end
  for i = 0, 7 do buf[off + i] = bytes[i] end
end

local function read_i64(stack, slot)
  return tonumber(ffi.cast("int64_t *", stack)[(slot or 0) * 2])
end

local function read_f64(stack, slot)
  return tonumber(ffi.cast("double *", stack)[(slot or 0) * 2])
end

local function f64_bytes_from_int(value)
  local n = tonumber(value) or 0
  if n == 0 then return {0, 0, 0, 0, 0, 0, 0, 0} end
  local sign = 0
  if n < 0 then sign = 0x80000000; n = -n end
  local exp = math.floor(math.log(n) / math.log(2))
  local pow = 2 ^ exp
  local mant = math.floor((n / pow - 1) * 2 ^ 52 + 0.5)
  local lo = mant % 4294967296
  local hi = sign + (exp + 1023) * 1048576 + math.floor(mant / 4294967296)
  return {
    lo % 256, math.floor(lo / 256) % 256, math.floor(lo / 65536) % 256, math.floor(lo / 16777216) % 256,
    hi % 256, math.floor(hi / 256) % 256, math.floor(hi / 65536) % 256, math.floor(hi / 16777216) % 256,
  }
end

local function write_f64_from_int(buf, off, v)
  local b = f64_bytes_from_int(v)
  for i = 0, 7 do buf[off + i] = b[i + 1] end
end

local function patch_immediates(buf, f, op)
  for _, dr in ipairs(f.data_relocs or {}) do
    if dr.reloc_kind == "abs64" and dr.role_kind == "imm" then
      local v = op.sbx or op.sBx or op.c or op.b or 0
      if op.op == "LOADF" then write_f64_from_int(buf, dr.code_offset, v) else write_i64(buf, dr.code_offset, v) end
    end
  end
end

local function patch_const_i64(buf, f, value)
  for _, dr in ipairs(f.data_relocs or {}) do
    if dr.reloc_kind == "abs64" and dr.role_kind == "const" then write_i64(buf, dr.code_offset, value) end
  end
end

local function executable_copy(buf, n)
  local PROT_READ, PROT_WRITE, PROT_EXEC = 1, 2, 4
  local MAP_PRIVATE, MAP_ANON = 2, 0x20
  local mem = ffi.C.mmap(nil, n, PROT_READ + PROT_WRITE + PROT_EXEC, MAP_PRIVATE + MAP_ANON, -1, 0)
  assert_true(mem ~= ffi.cast("void *", -1), "mmap failed")
  ffi.C.memcpy(mem, buf, n)
  return mem
end

local function lower_native(ops, facts)
  local r = SSA.compile(ops, facts or {})
  assert_true(r.ok, table.concat(r.errors or {}, "\n"))
  local fr = StencilLower.generate(r, { facts = facts or {} })
  assert_true(fr.ok, table.concat(fr.errors or {}, "\n"))
  assert_true(fr.stencil.executable == true and (fr.stencil.code_size or 0) > 0, "native stencil expected")
  return fr.stencil
end

local function run_native(f, patch, setup, check)
  local buf, n = hex_to_buf(f.code_hex)
  if patch then patch(buf, f) end
  local mem = executable_copy(buf, n)
  local fn = ffi.cast("void (*)(SponExecCtx *)", mem)
  local stack = ffi.new("SponTValueABI[8]")
  local k = ffi.new("SponTValueABI[4]")
  local ctx = ffi.new("SponExecCtx")
  ctx.stack = stack
  ctx.k = k
  if setup then setup(ctx, stack, k) end
  fn(ctx)
  if check then check(ctx, stack, k) end
  ffi.C.munmap(mem, n)
end

assert_eq(ffi.sizeof("SponTValueABI"), 16, "TValue ABI size")
assert_eq(ffi.offsetof("SponExecCtx", "exit_kind"), 16 + 256 * 16, "ctx exit offset")

local facts = { Facts.fact("type", Facts.slot("R1"), "is_i64", true) }
local f = lower_native({ { op = "ADDI", a = 1, b = 1, c = 7 } }, facts)
assert_true(f.executable == true, "stencil must be executable")
assert_true((f.code_size or 0) > 0 and type(f.code_hex) == "string", "native code bytes missing")
assert_eq(f.abi.stencil.flags, 10, "native exact flag")

local buf, n = hex_to_buf(f.code_hex)
local saw_abs64, saw_pc32, saw_slot_addend8 = false, false, false
for _, dr in ipairs(f.data_relocs or {}) do
  assert_true(dr.code_offset_kind ~= "abstract_zero", "data reloc must be real")
  if dr.reloc_kind == "abs64" and dr.role_kind == "imm" then write_i64(buf, dr.code_offset, 7); saw_abs64 = true end
  if dr.role_kind == "slot" and dr.addend == 8 then saw_slot_addend8 = true end
end
for _, cr in ipairs(f.control_relocs or {}) do
  assert_eq(cr.reloc_kind, "pc32", "control reloc must be rel32")
  saw_pc32 = true
end
assert_true(saw_abs64, "imm64 patch site missing")
assert_true(saw_pc32, "guard control patch site missing")
assert_true(saw_slot_addend8, "slot tag displacement patch site missing")

local mem = executable_copy(buf, n)
local fn = ffi.cast("void (*)(SponExecCtx *)", mem)
local stack = ffi.new("SponTValueABI[8]")
local ctx = ffi.new("SponExecCtx")
ctx.stack = stack

stack[0].value_ = 35
stack[0].tt_ = 3 -- LUA_VNUMINT
ctx.exit_kind = 99
fn(ctx)
assert_eq(tonumber(ctx.exit_kind), 0, "success exit kind")
assert_eq(tonumber(stack[0].value_), 42, "ADDI native result")
assert_eq(tonumber(stack[0].tt_), 3, "ADDI native result tag")

stack[0].value_ = 35
stack[0].tt_ = 0 -- not integer; guard must branch to local guard endpoint stub
ctx.exit_kind = 99
fn(ctx)
assert_eq(tonumber(ctx.exit_kind), 1, "guard exit kind")
assert_eq(tonumber(ctx.exit_pc), 1, "guard exit pc")

ffi.C.munmap(mem, n)

run_native(lower_native({ { op = "LOADTRUE", a = 0 } }), nil,
  function(ctx, stack) stack[0].value_ = 0; stack[0].tt_ = 0; ctx.exit_kind = 99 end,
  function(ctx, stack) assert_eq(tonumber(ctx.exit_kind), 0, "LOADTRUE exit"); assert_eq(tonumber(stack[0].tt_), 17, "LOADTRUE tag") end)

run_native(lower_native({ { op = "LOADNIL", a = 0 } }), nil,
  function(ctx, stack) stack[0].value_ = 123; stack[0].tt_ = 3; ctx.exit_kind = 99 end,
  function(ctx, stack) assert_eq(tonumber(ctx.exit_kind), 0, "LOADNIL exit"); assert_eq(tonumber(stack[0].tt_), 0, "LOADNIL tag") end)

run_native(lower_native({ { op = "MOVE", a = 0, b = 1 } }), nil,
  function(ctx, stack) stack[1].value_ = 12345; stack[1].tt_ = 3; ctx.exit_kind = 99 end,
  function(ctx, stack) assert_eq(tonumber(ctx.exit_kind), 0, "MOVE exit"); assert_eq(tonumber(stack[0].value_), 12345, "MOVE value"); assert_eq(tonumber(stack[0].tt_), 3, "MOVE tag") end)

run_native(lower_native({ { op = "LOADK", a = 0, b = 0 } }), nil,
  function(ctx, stack, k) k[0].value_ = 55; k[0].tt_ = 3; ctx.exit_kind = 99 end,
  function(ctx, stack) assert_eq(tonumber(ctx.exit_kind), 0, "LOADK exit"); assert_eq(tonumber(stack[0].value_), 55, "LOADK value"); assert_eq(tonumber(stack[0].tt_), 3, "LOADK tag") end)

local not_stencil = lower_native({ { op = "NOT", a = 0, b = 1 } })
run_native(not_stencil, nil,
  function(ctx, stack) stack[1].value_ = 0; stack[1].tt_ = 0; ctx.exit_kind = 99 end,
  function(ctx, stack) assert_eq(tonumber(ctx.exit_kind), 0, "NOT nil exit"); assert_eq(tonumber(stack[0].tt_), 17, "NOT nil true tag") end)
run_native(not_stencil, nil,
  function(ctx, stack) stack[1].value_ = 0; stack[1].tt_ = 1; ctx.exit_kind = 99 end,
  function(ctx, stack) assert_eq(tonumber(ctx.exit_kind), 0, "NOT false exit"); assert_eq(tonumber(stack[0].tt_), 17, "NOT false true tag") end)
run_native(not_stencil, nil,
  function(ctx, stack) stack[1].value_ = 0; stack[1].tt_ = 17; ctx.exit_kind = 99 end,
  function(ctx, stack) assert_eq(tonumber(ctx.exit_kind), 0, "NOT true exit"); assert_eq(tonumber(stack[0].tt_), 1, "NOT true false tag") end)
run_native(not_stencil, nil,
  function(ctx, stack) stack[1].value_ = 42; stack[1].tt_ = 3; ctx.exit_kind = 99 end,
  function(ctx, stack) assert_eq(tonumber(ctx.exit_kind), 0, "NOT int exit"); assert_eq(tonumber(stack[0].tt_), 1, "NOT int false tag") end)

local loadf = lower_native({ { op = "LOADF", a = 0, sbx = 42 } })
run_native(loadf,
  function(buf, f) patch_immediates(buf, f, { op = "LOADF", sbx = 42 }) end,
  function(ctx, stack) stack[0].value_ = 0; stack[0].tt_ = 0; ctx.exit_kind = 99 end,
  function(ctx, stack)
    local d = ffi.cast("double *", stack)[0]
    assert_eq(tonumber(ctx.exit_kind), 0, "LOADF exit")
    assert_eq(tonumber(stack[0].tt_), 19, "LOADF tag")
    assert_true(math.abs(d - 42.0) < 1e-12, "LOADF value")
  end)

local shift_facts = {
  Facts.fact("type", Facts.slot("R0"), "is_i64", true),
  Facts.fact("type", Facts.slot("R1"), "is_i64", true),
}
local shl = lower_native({ { op = "SHL", a = 0, b = 0, c = 1 } }, shift_facts)
run_native(shl, nil,
  function(ctx, stack) stack[0].value_ = 3; stack[0].tt_ = 3; stack[1].value_ = 2; stack[1].tt_ = 3; ctx.exit_kind = 99 end,
  function(ctx, stack) assert_eq(tonumber(ctx.exit_kind), 0, "SHL exit"); assert_eq(tonumber(stack[0].value_), 12, "SHL result") end)
local shr = lower_native({ { op = "SHR", a = 0, b = 0, c = 1 } }, shift_facts)
run_native(shr, nil,
  function(ctx, stack) stack[0].value_ = 16; stack[0].tt_ = 3; stack[1].value_ = 2; stack[1].tt_ = 3; ctx.exit_kind = 99 end,
  function(ctx, stack) assert_eq(tonumber(ctx.exit_kind), 0, "SHR exit"); assert_eq(tonumber(stack[0].value_), 4, "SHR result") end)
local shli = lower_native({ { op = "SHLI", a = 0, b = 1, c = 3 } }, { Facts.fact("type", Facts.slot("R1"), "is_i64", true) })
run_native(shli,
  function(buf, f) patch_immediates(buf, f, { op = "SHLI", c = 3 }) end,
  function(ctx, stack) stack[1].value_ = 2; stack[1].tt_ = 3; ctx.exit_kind = 99 end,
  function(ctx, stack) assert_eq(tonumber(ctx.exit_kind), 0, "SHLI exit"); assert_eq(tonumber(stack[0].value_), 12, "SHLI result") end)
local shri = lower_native({ { op = "SHRI", a = 0, b = 0, c = 2 } }, { Facts.fact("type", Facts.slot("R0"), "is_i64", true) })
run_native(shri,
  function(buf, f) patch_immediates(buf, f, { op = "SHRI", c = 2 }) end,
  function(ctx, stack) stack[0].value_ = 16; stack[0].tt_ = 3; ctx.exit_kind = 99 end,
  function(ctx, stack) assert_eq(tonumber(ctx.exit_kind), 0, "SHRI exit"); assert_eq(tonumber(stack[0].value_), 4, "SHRI result") end)

local div_facts = {
  Facts.fact("type", Facts.slot("R0"), "is_i64", true),
  Facts.fact("type", Facts.slot("R1"), "is_i64", true),
}
local idiv = lower_native({ { op = "IDIV", a = 0, b = 0, c = 1 } }, div_facts)
run_native(idiv, nil,
  function(ctx, stack) stack[0].value_ = ffi.cast("uint64_t", -7); stack[0].tt_ = 3; stack[1].value_ = 3; stack[1].tt_ = 3; ctx.exit_kind = 99 end,
  function(ctx, stack) assert_eq(tonumber(ctx.exit_kind), 0, "IDIV exit"); assert_eq(read_i64(stack, 0), -3, "IDIV floors negative quotient"); assert_eq(tonumber(stack[0].tt_), 3, "IDIV tag") end)
run_native(idiv, nil,
  function(ctx, stack) stack[0].value_ = 7; stack[0].tt_ = 3; stack[1].value_ = 0; stack[1].tt_ = 3; ctx.exit_kind = 99 end,
  function(ctx) assert_eq(tonumber(ctx.exit_kind), 1, "IDIV zero divisor guard"); assert_eq(tonumber(ctx.exit_pc), 1, "IDIV guard pc") end)
local mod = lower_native({ { op = "MOD", a = 0, b = 0, c = 1 } }, div_facts)
run_native(mod, nil,
  function(ctx, stack) stack[0].value_ = ffi.cast("uint64_t", -7); stack[0].tt_ = 3; stack[1].value_ = 3; stack[1].tt_ = 3; ctx.exit_kind = 99 end,
  function(ctx, stack) assert_eq(tonumber(ctx.exit_kind), 0, "MOD exit"); assert_eq(read_i64(stack, 0), 2, "MOD follows Lua floor-mod semantics"); assert_eq(tonumber(stack[0].tt_), 3, "MOD tag") end)
local div = lower_native({ { op = "DIV", a = 0, b = 0, c = 1 } }, div_facts)
run_native(div, nil,
  function(ctx, stack) stack[0].value_ = 7; stack[0].tt_ = 3; stack[1].value_ = 2; stack[1].tt_ = 3; ctx.exit_kind = 99 end,
  function(ctx, stack) assert_eq(tonumber(ctx.exit_kind), 0, "DIV exit"); assert_eq(tonumber(stack[0].tt_), 19, "DIV result is float"); assert_true(math.abs(read_f64(stack, 0) - 3.5) < 1e-12, "DIV value") end)

local divk_facts = {
  Facts.fact("type", Facts.slot("R0"), "is_i64", true),
  Facts.fact("assumed", Facts.value("K1"), "const_i64", true),
}
local idivk = lower_native({ { op = "IDIVK", a = 0, b = 0, c = 1 } }, divk_facts)
run_native(idivk,
  function(buf, f) patch_const_i64(buf, f, 3) end,
  function(ctx, stack) stack[0].value_ = ffi.cast("uint64_t", -7); stack[0].tt_ = 3; ctx.exit_kind = 99 end,
  function(ctx, stack) assert_eq(tonumber(ctx.exit_kind), 0, "IDIVK exit"); assert_eq(read_i64(stack, 0), -3, "IDIVK floors negative quotient") end)
local modk = lower_native({ { op = "MODK", a = 0, b = 0, c = 1 } }, divk_facts)
run_native(modk,
  function(buf, f) patch_const_i64(buf, f, 3) end,
  function(ctx, stack) stack[0].value_ = ffi.cast("uint64_t", -7); stack[0].tt_ = 3; ctx.exit_kind = 99 end,
  function(ctx, stack) assert_eq(tonumber(ctx.exit_kind), 0, "MODK exit"); assert_eq(read_i64(stack, 0), 2, "MODK floor mod") end)
local divk = lower_native({ { op = "DIVK", a = 0, b = 0, c = 1 } }, divk_facts)
run_native(divk,
  function(buf, f) patch_const_i64(buf, f, 2) end,
  function(ctx, stack) stack[0].value_ = 7; stack[0].tt_ = 3; ctx.exit_kind = 99 end,
  function(ctx, stack) assert_eq(tonumber(ctx.exit_kind), 0, "DIVK exit"); assert_eq(tonumber(stack[0].tt_), 19, "DIVK tag"); assert_true(math.abs(read_f64(stack, 0) - 3.5) < 1e-12, "DIVK value") end)

local cmp_boundary = lower_native({ { op = "TEST", a = 0, b = 0, c = 0 } })
run_native(cmp_boundary, nil,
  function(ctx) ctx.exit_kind = 99 end,
  function(ctx) assert_eq(tonumber(ctx.exit_kind), 2, "TEST boundary exit"); assert_eq(tonumber(ctx.exit_pc), 1, "TEST boundary pc") end)

for _, bop in ipairs({
  { op = "LEN", a = 0, b = 1 },
  { op = "CONCAT", a = 0, b = 0, c = 2 },
  { op = "MMBIN", a = 0, b = 1, c = 0 },
  { op = "MMBINI", a = 0, b = 1, c = 0 },
  { op = "MMBINK", a = 0, b = 1, c = 0 },
  { op = "CLOSE", a = 0 },
  { op = "TBC", a = 0 },
  { op = "NEWTABLE", a = 0, b = 0, c = 0 },
  { op = "SETLIST", a = 0, b = 0, c = 0 },
  { op = "CLOSURE", a = 0, bx = 0 },
  { op = "VARARG", a = 0, c = 0 },
  { op = "GETVARG", a = 0, c = 0 },
  { op = "ERRNNIL", a = 0 },
  { op = "VARARGPREP", a = 0 },
  { op = "EXTRAARG", ax = 0 },
}) do
  local bf = lower_native({ bop })
  assert_eq(bf.semantic_mode, "boundary", bop.op .. " semantic boundary")
  run_native(bf, nil,
    function(ctx) ctx.exit_kind = 99 end,
    function(ctx) assert_eq(tonumber(ctx.exit_kind), 2, bop.op .. " boundary exit"); assert_eq(tonumber(ctx.exit_pc), 1, bop.op .. " boundary pc") end)
end

local unsupported = SSA.compile({ { op = "GETUPVAL", a = 0, b = 0 } }, {})
assert_true(not unsupported.ok, "GETUPVAL must remain explicit missing coverage")
local unsupported_table = SSA.compile({ { op = "GETTABLE", a = 0, b = 0, c = 1 } }, {})
assert_true(not unsupported_table.ok, "GETTABLE without table/array payload facts must remain explicit missing coverage")

print("ok - SpongeJIT native stencil bytes execute")

#!/usr/bin/env luajit

package.path = "./?.lua;./?/init.lua;./experiments/lua_interpreter_vm/spongejit/?.lua;" .. package.path

local ffi = require("ffi")
local bit = require("bit")
local Materialize = require("src.materialize_native_x64")
local Constants = require("experiments.lua_interpreter_vm.src.constants")

ffi.cdef[[
typedef unsigned int uint32_t;
typedef unsigned short uint16_t;
typedef int int32_t;
typedef unsigned long long uint64_t;
typedef uint64_t SponFactSig;
typedef uint32_t SponStencilId;

typedef struct SponTValueABI {
  unsigned long long value_;
  unsigned char tt_;
} SponTValueABI;
typedef struct SponExecCtx {
  void *stack;
  SponTValueABI *k;
  SponTValueABI scratch[256];
  uint32_t exit_kind;
  uint32_t exit_pc;
  uint32_t exit_op_idx;
  uint32_t exit_hole;
} SponExecCtx;

typedef struct {
  SponStencilId stencil_id;
  uint32_t pc_start;
  uint32_t pc_end;
} SponStencilChoice;

typedef struct {
  uint64_t pattern_probes;
  uint64_t candidate_checks;
  uint32_t choices;
  uint32_t status;
  uint32_t covered_end;
  uint32_t first_uncovered_pc;
  uint32_t no_candidate_opcode;
} SponSelectStats;

typedef struct {
  uint32_t code_offset;
  uint16_t reloc_kind;
  uint16_t role_kind;
  uint16_t op_idx;
  int32_t role_arg;
  int32_t addend;
} SponDataReloc;

typedef struct {
  uint32_t code_offset;
  uint16_t reloc_kind;
  uint16_t edge_kind;
  uint16_t endpoint_index;
  int32_t target_delta;
} SponControlReloc;

typedef struct {
  uint16_t op_idx;
  uint8_t logical_slot;
  uint8_t field_kind;
} SponSlotMapEntry;

typedef struct {
  SponStencilId stencil_id;
  uint32_t offset;
  uint32_t size;
  uint32_t endpoint_start;
  uint32_t data_reloc_start;
  uint32_t control_reloc_start;
