local bank_path = "experiments/lua_interpreter_vm/spongejit/build/sponbank/libsponbank.so"
local f = io.open(bank_path, "rb")
assert(f, "missing generated L1 bank: " .. bank_path)
f:close()

local bank = ffi.load(bank_path)
assert(bank.spon_bank_stencil_count() > 0, "empty generated bank")

local op_name = {}
for name, opcode in pairs(Constants.Op) do
  if type(opcode) == "number" and not op_name[opcode] then op_name[opcode] = name end
end

local strict = os.getenv("SPON_STRICT_SEMANTIC_L0") == "1"
local missing, bad = {}, {}
for opcode = 0, 84 do
  local id = tonumber(bank.spon_l0_stencil_for_opcode(opcode))
  local name = op_name[opcode] or ("OP_" .. tostring(opcode))
  if id == 0 then
    missing[#missing + 1] = string.format("%d:%s", opcode, name)
  else
    local d = bank.spon_get_stencil(id)
    local data = bank.spon_stencil_data(id)
    if d == nil then
      bad[#bad + 1] = string.format("%d:%s id=%d missing descriptor", opcode, name, id)
    elseif bit.band(tonumber(d.flags), 10) ~= 10 then
      bad[#bad + 1] = string.format("%d:%s id=%d not exact native flags=%d", opcode, name, id, tonumber(d.flags))
    elseif tonumber(d.size) <= 0 or data == nil then
      bad[#bad + 1] = string.format("%d:%s id=%d no native bytes", opcode, name, id)
    else
      local nrel = ffi.new("uint32_t[1]")
      local rels = bank.spon_stencil_control_relocs(id, nrel)
      for i = 0, tonumber(nrel[0]) - 1 do
        local edge = tonumber(rels[i].edge_kind)
        if edge < 1 or edge > 4 then
          bad[#bad + 1] = string.format("%d:%s id=%d unknown control edge=%d", opcode, name, id, edge)
        end
      end
    end
  end
end

assert(#bad == 0, "bad semantic L0 bank entries: " .. table.concat(bad, "; "))
if strict then
  assert(#missing == 0, "strict semantic L0 coverage missing opcodes: " .. table.concat(missing, ", "))
else
  io.stderr:write(string.format("[semantic-l0] exact native L0 entries=%d missing=%d\n", 85 - #missing, #missing))
end

print("ok - SpongeJIT generated bank reports truthful semantic L0 coverage")

